INSERT INTO `product` (`id`, `title`, `image`, `description`, `content`, `sell`, `view`, `rating`, `status`, `priority`, `tags`, `template`, `stock_manage`, `stop_selling`, `stock_quant`, `option_1`, `option_2`, `option_3`, `option_4`, `option_5`, `option_6`, `created_at`, `updated_at`, `raw_title`, `raw_full`) VALUES
(374, 'TP-Lmuc Archer AX55', 'TP-Lmuc Archer AX55.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'internet', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:40:00', '2024-05-14 04:40:00', 'tp-lmuc archer ax55', 'tp-lmuc archer ax55 bộ định tuyến wifi 6 phổ biến được thiết kế cho mạng gia đình và van-phong tốc độ cao. có tốc độ ax3000 băng tần kép, cổng gigabit wan/lan, công nghệ ofdma và mu-mimo, bảo mật wpa3, hỗ trợ onemesh, kiểm soát của phụ huynh và phạm vi phủ sóng mạnh mẽ cho môi trường chơi game và phát trực tuyến.'),
(375, 'ASUS RT-AX52', 'ASUS RT-AX52.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'internet', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:40:00', '2024-05-14 04:40:00', 'asus rt-ax52', 'asus rt-ax52 bộ định tuyến wifi 6 được mua rộng rãi với tốc độ băng tần kép ax1800, bảo mật asus aiprotection, kiểm soát của phụ huynh, cổng gigabit ethernet, hỗ trợ ofdma, khả năng tương thích lưới và hiệu suất không dây ổn định cho gia đình và xe van.'),
(376, 'TP-Lmuc Archer C54', 'TP-Lmuc Archer C54.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'internet', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:40:00', '2024-05-14 04:40:00', 'tp-lmuc archer c54', 'tp-lmuc archer c54 bộ định tuyến wifi băng tần kép ac1200 giá cả phải chăng được thiết kế để sử dụng internet hàng ngày. có bốn ăng-ten bên ngoài, kiểm soát của phụ huynh, hỗ trợ mạng khách, khả năng tương thích iptv và vùng phủ sóng không dây đáng tin cậy cho những ngôi nhà nhỏ và xe van-phong.'),
(377, 'NETGEAR Nighthawk RAX50', 'NETGEAR Nighthawk RAX50.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'internet', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:40:00', '2024-05-14 04:40:00', 'netgear nighthawk rax50', 'netgear nighthawk rax50 bộ định tuyến wifi 6 hiệu suất cao được thiết kế để chơi game và phát trực tuyến. có tốc độ ax5400, kết nối băng tần kép, bảo vệ bảo mật nâng cao, cổng gigabit ethernet, hỗ trợ usb 3.0 và hiệu suất không dây đa thiết bị mạnh mẽ.'),
(378, 'Mercusys MW302R', 'Mercusys MW302R.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'internet', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:40:00', '2024-05-14 04:40:00', 'mercusys mw302r', 'mercusys mw302r bộ định tuyến không dây thân thiện với ngân sách được thiết kế cho mạng gia đình và van-phong cơ bản. có tốc độ không dây 300mbps, ăng-ten kép bên ngoài, thiết kế nhỏ gọn, thiết lập dễ dàng và chia sẻ internet đáng tin cậy cho không gian nhỏ.'),
(379, 'UGREEN Cat6 Ethernet Cable', 'UGREEN Cat6 Ethernet Cable.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'internet', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:40:00', '2024-05-14 04:40:00', 'ugreen cat6 ethernet cable', 'ugreen cat6 ethernet cable cáp internet cat6 tốc độ cao được thiết kế để kết nối mạng gigabit ổn định. có đầu nối rj45, tốc độ truyền lên đến 1000mbps, che chắn chống nhiễu, áo khoác pvc bền và khả năng tương thích với bộ định tuyến, pc, thiết bị chuyển mạch và bảng điều khiển trò chơi.'),
(380, 'Vention Cat6 Ethernet Cable', 'Vention Cat6 Ethernet Cable.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'internet', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:40:00', '2024-05-14 04:40:00', 'vention cat6 ethernet cable', 'vention cat6 ethernet cable cáp mạng cat6 phổ biến được thiết kế để kết nối internet có dây đáng tin cậy. có lõi đồng nguyên chất, đầu nối rj45, hỗ trợ tốc độ gigabit, che chắn chống ồn, kết cấu bện bền và khả năng tương thích với bộ định tuyến và hệ thống máy tính để bàn.'),
(381, 'AMP CAT6 UTP Cable', 'AMP CAT6 UTP Cable.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'internet', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:40:00', '2024-05-14 04:40:00', 'amp cat6 utp cable', 'amp cat6 utp cable cáp mạng cat6 cấp chuyên nghiệp được thiết kế cho mạng van-phong và doanh nghiệp. có dây dẫn bằng đồng nguyên chất, truyền dữ liệu gigabit ổn định, cách điện bền, truyền nhiễu thấp và hỗ trợ cài đặt mạng có cấu trúc.'),
(382, 'Dintek CAT6 Patch Cord', 'Dintek CAT6 Patch Cord.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'internet', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:40:00', '2024-05-14 04:40:00', 'dintek cat6 patch cord', 'dintek cat6 patch cord cáp mạng được sử dụng rộng rãi có hỗ trợ gigabit ethernet tốc độ cao, đầu nối rj45 đúc, kết cấu bền linh hoạt, truyền tín hiệu ổn định và khả năng tương thích với thiết bị chuyển mạch, bộ định tuyến, pc và hệ thống mạng doanh nghiệp.'),
(383, 'Belkin Cat6 Ethernet Cable', 'Belkin Cat6 Ethernet Cable.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'internet', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:40:00', '2024-05-14 04:40:00', 'belkin cat6 ethernet cable', 'belkin cat6 ethernet cable cáp internet cat6 cao cấp được thiết kế để kết nối mạng tốc độ cao đáng tin cậy. có hỗ trợ gigabit ethernet, đầu nối rj45, lớp phủ pvc bền, che chắn chống nhiễu và kết nối có dây ổn định cho các thiết lập van-phong và chơi game.'),
(384, 'TP-Lmuc TL-SG108', 'TP-Lmuc TL-SG108.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'internet', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:40:00', '2024-05-14 04:40:00', 'tp-lmuc tl-sg108', 'tp-lmuc tl-sg108 một trong những thiết bị chuyển mạch gigabit không được quản lý phổ biến nhất trên thế giới có 8 cổng gigabit ethernet, thiết lập plug-and-play, vỏ kim loại, công nghệ tiết kiệm năng lượng, hoạt động im lặng không quạt và hiệu suất mạng gia đình đáng tin cậy.'),
(385, 'TP-Lmuc TL-SG1005D', 'TP-Lmuc TL-SG1005D.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'internet', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:40:00', '2024-05-14 04:40:00', 'tp-lmuc tl-sg1005d', 'tp-lmuc tl-sg1005d bộ chuyển mạch máy tính để bàn gigabit 5 cổng nhỏ gọn được thiết kế để mở rộng gia đình và van-phong. tính năng cài đặt plug-and-play, hoạt động im lặng không quạt, công nghệ tiết kiệm năng lượng, thiết kế máy tính để bàn nhỏ gọn và hiệu suất mạng có dây ổn định.'),
(386, 'Netgear ProSafe GS105', 'Netgear ProSafe GS105.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'internet', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:40:00', '2024-05-14 04:40:00', 'netgear prosafe gs105', 'netgear prosafe gs105 bộ chuyển mạch gigabit không được quản lý đáng tin cậy được thiết kế cho mạng van-phong và doanh nghiệp. có 5 cổng gigabit ethernet, khung kim loại, hoạt động không quạt, kết nối plug-and-play, hiệu suất tiết kiệm năng lượng và thiết kế thương mại bền bỉ.'),
(387, 'Cisco CBS110-8T-D', 'Cisco CBS110-8T-D.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'internet', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:40:00', '2024-05-14 04:40:00', 'cisco cbs110-8t-d', 'cisco cbs110-8t-d bộ chuyển mạch mạng không được quản lý cấp doanh nghiệp được thiết kế cho các xe tải nhỏ và mạng doanh nghiệp. có 8 cổng gigabit ethernet, hoạt động tiết kiệm năng lượng, thiết kế nhỏ gọn, cài đặt plug-and-play và hiệu suất mạng thương mại đáng tin cậy.'),
(388, 'D-Lmuc DGS-108', 'D-Lmuc DGS-108.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'internet', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:40:00', '2024-05-14 04:40:00', 'd-lmuc dgs-108', 'd-lmuc dgs-108 bộ chuyển mạch gigabit 8 cổng được mua rộng rãi được thiết kế cho van-phong và mạng có dây gia đình. có vỏ kim loại, thiết lập plug-and-play, tối ưu hóa lưu lượng qos, hoạt động im lặng không quạt và hiệu suất gigabit ethernet tiết kiệm năng lượng.');
