INSERT INTO `product_translations` (`id`, `product_id`, `lang`, `title`, `description`, `content`, `created_at`, `updated_at`) VALUES
(374, 374, 'vi', 'TP-Lmuc Archer AX55', '', '<p>Bộ định tuyến WiFi 6 phổ biến được thiết kế cho mạng gia đình và van-phong tốc độ cao. Có tốc độ AX3000 băng tần kép, cổng Gigabit WAN/LAN, công nghệ OFDMA và MU-MIMO, bảo mật WPA3, hỗ trợ OneMesh, kiểm soát của phụ huynh và phạm vi phủ sóng mạnh mẽ cho môi trường chơi game và phát trực tuyến.</p>', '2024-05-14 04:40:00', '2024-05-14 04:40:00'),
(375, 375, 'vi', 'ASUS RT-AX52', '', '<p>Bộ định tuyến WiFi 6 được mua rộng rãi với tốc độ băng tần kép AX1800, bảo mật ASUS AiProtection, kiểm soát của phụ huynh, cổng Gigabit Ethernet, hỗ trợ OFDMA, khả năng tương thích lưới và hiệu suất không dây ổn định cho gia đình và xe van.</p>', '2024-05-14 04:40:00', '2024-05-14 04:40:00'),
(376, 376, 'vi', 'TP-Lmuc Archer C54', '', '<p>Bộ định tuyến WiFi băng tần kép AC1200 giá cả phải chăng được thiết kế để sử dụng internet hàng ngày. Có bốn ăng-ten bên ngoài, kiểm soát của phụ huynh, hỗ trợ mạng khách, khả năng tương thích IPTV và vùng phủ sóng không dây đáng tin cậy cho những ngôi nhà nhỏ và xe van-phong.</p>', '2024-05-14 04:40:00', '2024-05-14 04:40:00'),
(377, 377, 'vi', 'NETGEAR Nighthawk RAX50', '', '<p>Bộ định tuyến WiFi 6 hiệu suất cao được thiết kế để chơi game và phát trực tuyến. Có tốc độ AX5400, kết nối băng tần kép, bảo vệ bảo mật nâng cao, cổng Gigabit Ethernet, hỗ trợ USB 3.0 và hiệu suất không dây đa thiết bị mạnh mẽ.</p>', '2024-05-14 04:40:00', '2024-05-14 04:40:00'),
(378, 378, 'vi', 'Mercusys MW302R', '', '<p>Bộ định tuyến không dây thân thiện với ngân sách được thiết kế cho mạng gia đình và van-phong cơ bản. Có tốc độ không dây 300Mbps, ăng-ten kép bên ngoài, thiết kế nhỏ gọn, thiết lập dễ dàng và chia sẻ internet đáng tin cậy cho không gian nhỏ.</p>', '2024-05-14 04:40:00', '2024-05-14 04:40:00'),
(379, 379, 'vi', 'UGREEN Cat6 Ethernet Cable', '', '<p>Cáp internet Cat6 tốc độ cao được thiết kế để kết nối mạng Gigabit ổn định. Có đầu nối RJ45, tốc độ truyền lên đến 1000Mbps, che chắn chống nhiễu, áo khoác PVC bền và khả năng tương thích với bộ định tuyến, PC, thiết bị chuyển mạch và bảng điều khiển trò chơi.</p>', '2024-05-14 04:40:00', '2024-05-14 04:40:00'),
(380, 380, 'vi', 'Vention Cat6 Ethernet Cable', '', '<p>Cáp mạng Cat6 phổ biến được thiết kế để kết nối internet có dây đáng tin cậy. Có lõi đồng nguyên chất, đầu nối RJ45, hỗ trợ tốc độ Gigabit, che chắn chống ồn, kết cấu bện bền và khả năng tương thích với bộ định tuyến và hệ thống máy tính để bàn.</p>', '2024-05-14 04:40:00', '2024-05-14 04:40:00'),
(381, 381, 'vi', 'AMP CAT6 UTP Cable', '', '<p>Cáp mạng CAT6 cấp chuyên nghiệp được thiết kế cho mạng van-phong và doanh nghiệp. Có dây dẫn bằng đồng nguyên chất, truyền dữ liệu Gigabit ổn định, cách điện bền, truyền nhiễu thấp và hỗ trợ cài đặt mạng có cấu trúc.</p>', '2024-05-14 04:40:00', '2024-05-14 04:40:00'),
(382, 382, 'vi', 'Dintek CAT6 Patch Cord', '', '<p>Cáp mạng được sử dụng rộng rãi có hỗ trợ Gigabit Ethernet tốc độ cao, đầu nối RJ45 đúc, kết cấu bền linh hoạt, truyền tín hiệu ổn định và khả năng tương thích với thiết bị chuyển mạch, bộ định tuyến, PC và hệ thống mạng doanh nghiệp.</p>', '2024-05-14 04:40:00', '2024-05-14 04:40:00'),
(383, 383, 'vi', 'Belkin Cat6 Ethernet Cable', '', '<p>Cáp internet Cat6 cao cấp được thiết kế để kết nối mạng tốc độ cao đáng tin cậy. Có hỗ trợ Gigabit Ethernet, đầu nối RJ45, lớp phủ PVC bền, che chắn chống nhiễu và kết nối có dây ổn định cho các thiết lập van-phong và chơi game.</p>', '2024-05-14 04:40:00', '2024-05-14 04:40:00'),
(384, 384, 'vi', 'TP-Lmuc TL-SG108', '', '<p>Một trong những thiết bị chuyển mạch Gigabit không được quản lý phổ biến nhất trên thế giới có 8 cổng Gigabit Ethernet, thiết lập plug-and-play, vỏ kim loại, công nghệ tiết kiệm năng lượng, hoạt động im lặng không quạt và hiệu suất mạng gia đình đáng tin cậy.</p>', '2024-05-14 04:40:00', '2024-05-14 04:40:00'),
(385, 385, 'vi', 'TP-Lmuc TL-SG1005D', '', '<p>Bộ chuyển mạch máy tính để bàn Gigabit 5 cổng nhỏ gọn được thiết kế để mở rộng gia đình và van-phong. Tính năng cài đặt plug-and-play, hoạt động im lặng không quạt, công nghệ tiết kiệm năng lượng, thiết kế máy tính để bàn nhỏ gọn và hiệu suất mạng có dây ổn định.</p>', '2024-05-14 04:40:00', '2024-05-14 04:40:00'),
(386, 386, 'vi', 'Netgear ProSafe GS105', '', '<p>Bộ chuyển mạch Gigabit không được quản lý đáng tin cậy được thiết kế cho mạng van-phong và doanh nghiệp. Có 5 cổng Gigabit Ethernet, khung kim loại, hoạt động không quạt, kết nối plug-and-play, hiệu suất tiết kiệm năng lượng và thiết kế thương mại bền bỉ.</p>', '2024-05-14 04:40:00', '2024-05-14 04:40:00'),
(387, 387, 'vi', 'Cisco CBS110-8T-D', '', '<p>Bộ chuyển mạch mạng không được quản lý cấp doanh nghiệp được thiết kế cho các xe tải nhỏ và mạng doanh nghiệp. Có 8 cổng Gigabit Ethernet, hoạt động tiết kiệm năng lượng, thiết kế nhỏ gọn, cài đặt plug-and-play và hiệu suất mạng thương mại đáng tin cậy.</p>', '2024-05-14 04:40:00', '2024-05-14 04:40:00'),
(388, 388, 'vi', 'D-Lmuc DGS-108', '', '<p>Bộ chuyển mạch Gigabit 8 cổng được mua rộng rãi được thiết kế cho van-phong và mạng có dây gia đình. Có vỏ kim loại, thiết lập plug-and-play, tối ưu hóa lưu lượng QoS, hoạt động im lặng không quạt và hiệu suất Gigabit Ethernet tiết kiệm năng lượng.</p>', '2024-05-14 04:40:00', '2024-05-14 04:40:00');
